// W6 — Build Input
// Edita los valores de `input` para probar distintos payloads.
//
// CONVENCIONES DEV:
//   - canal y id_evento solo se usan para id_evento_dev (trazabilidad de pruebas)
//   - W6 NO genera idempotency_key. La función crear_bloqueo() no la espera.
//     Tampoco implementa idempotent_match: re-ejecutar el mismo payload sobre
//     un bloqueo ya creado rebota con error 'bloqueo_solapado'.
//   - source_event fijo: "n8n_w06_crear_bloqueo_manual"
//
// MODOS DE BLOQUEO:
//   - Específico: id_cabana = número (1-5) → bloquea solo esa cabaña
//   - Total:      id_cabana = null         → bloquea las 5 cabañas (complejo cerrado)
//
// MOTIVOS VÁLIDOS (enum implícito + CHECK constraint en bloqueos):
//   - "mantenimiento"
//   - "uso_propio"
//   - "tormenta"
//   - "overbooking"
//   - "otro"
//   Cualquier otro valor rebota con error 'motivo_invalido'.
//
// CAMPOS OBLIGATORIOS (la función rebota con 'payload_invalido' si faltan):
//   fecha_desde, fecha_hasta, motivo, creado_por, source_event
//
// CAMPOS OPCIONALES:
//   id_cabana (null para bloqueo total), descripcion
//
// FECHAS: formato YYYY-MM-DD. fecha_hasta es exclusive (igual que reservas).
// fecha_hasta debe ser > fecha_desde (CHECK constraint y validación interna).

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  // Identificación del evento (solo para trazabilidad de pruebas)
  canal: "manual_dev",
  id_evento: "test_w06_001",

  // Modo del bloqueo: número (específico) o null (total)
  id_cabana: 19,  // ← Arrebol (libre, sin reservas) para happy path específico

  // Fechas (YYYY-MM-DD)
  fecha_desde: "2026-09-15",
  fecha_hasta: "2026-09-18",  // exclusive

  // Motivo (obligatorio, enum)
  motivo: "mantenimiento",

  // Operador que crea el bloqueo (obligatorio)
  creado_por: "rodrigo_manual",

  // Descripción libre (opcional, queda en log_cambios)
  descripcion: "Pintura y reparaciones generales - test W6 happy path específico"
};
// =============================================

return [{ json: input }];

// W6 — Build Payload
// Toma el input editable de Build Input y construye:
//   1. source_event (convención 6C v1.2 Sección 5.5):
//        n8n_w06_crear_bloqueo_manual
//   2. id_evento_dev: solo para trazabilidad de pruebas en el wrapper
//      (NO se manda a la función SQL).
//   3. payload JSONB según contrato de crear_bloqueo(jsonb).
//
// CONTRATO PAYLOAD:
//   Obligatorios: fecha_desde, fecha_hasta, motivo, creado_por, source_event
//   Opcionales:   id_cabana (null = bloqueo total, número = específico),
//                 descripcion
//
// W6 NO genera idempotency_key. La función no la espera ni implementa
// idempotent_match.
//
// NORMALIZACIÓN DEFENSIVA (continuación de patrón W3/W4/W5):
// Aplicamos nv() a todos los campos. Particularmente importante para id_cabana:
//   - Si input.id_cabana viene como "" o undefined, nv() lo convierte a null
//     → modo bloqueo total
//   - Si viene como número, queda tal cual → modo específico
//
// IMPORTANTE sobre id_cabana = 0:
// La función no trata 0 como caso especial. Si por error mandamos id_cabana=0,
// la función intenta buscar la cabaña 0 (que no existe) y rebota con
// 'cabana_no_existe'. Por eso para bloqueo total se debe usar null explícito,
// NO el patrón 0=todas que usamos en W1.

const input = $input.first().json;

const source_event = 'n8n_w06_crear_bloqueo_manual';
const id_evento_dev = `${input.canal}_${input.id_evento}`;

const nv = (v) => (v === '' || v === undefined ? null : v);

const payload = {
  // Modo (null = total, número = específico)
  id_cabana: nv(input.id_cabana),

  // Obligatorios (con normalización defensiva)
  fecha_desde: nv(input.fecha_desde),
  fecha_hasta: nv(input.fecha_hasta),
  motivo: nv(input.motivo),
  creado_por: nv(input.creado_por),
  source_event,

  // Opcionales
  descripcion: nv(input.descripcion)
};

return [{
  json: {
    payload,
    source_event,
    id_evento_dev,
    input  // se preserva para trazabilidad en Build Response
  }
}];

// W6 — Build Response
// Interpreta el JSONB que devuelve crear_bloqueo() y arma el wrapper externo.
//
// Contrato de salida de la función:
//   - happy: { ok: true, id_bloqueo, id_cabana, tipo_bloqueo }
//                tipo_bloqueo: 'cabana_especifica' | 'total'
//   - error: { ok: false, error: '<codigo>', ...detalle según error }
//
// CONVENCIONES DEL WRAPPER:
//   - ok = resultado.ok
//   - error solo se llena cuando resultado.ok = false
//   - id_evento_dev para trazabilidad de pruebas
//   - result siempre lleva el JSONB completo de la función (incluye arrays
//     de IDs en conflicto cuando aplica: reservas_en_conflicto,
//     prereservas_en_conflicto, bloqueos_en_conflicto)
//
// W6 NO incluye idempotency_key (no aplica) ni warning (la función no emite).

const buildPayload = $('Build Payload').first().json;
const pgItem = items[0]?.json;
const resultado = pgItem?.resultado;

if (!resultado || typeof resultado !== 'object') {
  return [{
    json: {
      ok: false,
      workflow: 'vita_w06_crear_bloqueo_supabase',
      source_event: buildPayload.source_event,
      id_evento_dev: buildPayload.id_evento_dev,
      error: 'sin_respuesta_de_funcion',
      result: null,
      executed_at: new Date().toISOString()
    }
  }];
}

const ok = resultado.ok === true;

return [{
  json: {
    ok,
    workflow: 'vita_w06_crear_bloqueo_supabase',
    source_event: buildPayload.source_event,
    id_evento_dev: buildPayload.id_evento_dev,
    error: ok ? null : (resultado.error || 'error_desconocido'),
    result: resultado,
    executed_at: new Date().toISOString()
  }
}];
